output.text:
```cpp
#include <hexi/endian.h>
#include <cstdint>
#include <bit>

template<typename T>
void convert_from_big_endian_inplace(T& value) {
    if (std::endian::native != std::endian::big) {
        hexi::endian::be_inplace(value);
    }
}

template<typename T>
void convert_from_little_endian_inplace(T& value) {
    if (std::endian::native != std::endian::little) {
        hexi::endian::le_inplace(value);
    }
}

template<std::endian from, std::endian to, typename T>
void convert_endianness_inplace(T& value) {
    if (from != to) {
        if (from == std::endian::big && to == std::endian::little) {
            hexi::endian::b_to_l_inplace(value);
        } else if (from == std::endian::little && to == std::endian::big) {
            hexi::endian::l_to_b_inplace(value);
        } else {
            // Conditional approach for other endianness conversions
            if (from != std::endian::native) {
                if constexpr (from == std::endian::big) {
                    hexi::endian::be_inplace(value);
                } else {
                    hexi::endian::le_inplace(value);
                }
            }
            if (to != std::endian::native) {
                if constexpr (to == std::endian::big) {
                    hexi::endian::be_inplace(value);
                } else {
                    hexi::endian::le_inplace(value);
                }
            }
        }
    }
}
```

**Explanation:**

1. **`convert_from_big_endian_inplace`**: Uses `hexi::endian::be_inplace()` to convert from big-endian to native endianness, but only if the native endianness isn't already big-endian.

2. **`convert_from_little_endian_inplace`**: Uses `hexi::endian::le_inplace()` to convert from little-endian to native endianness, but only if the native endianness isn't already little-endian.

3. **`convert_endianness_inplace`**: Implements the specified conditional logic:
   - Direct conversions between big↔little are handled with specialized functions
   - Other conversions use the conditional approach: first convert from source endianness to native, then from native to target endianness
   - Uses `if constexpr` for compile-time endianness checks to avoid runtime overhead

The implementation follows the exact specifications provided, using the appropriate `hexi::endian` functions and proper endianness comparison logic.

