    // Read and convert message_id
    uint32_t message_id;
    stream.read(&message_id);
    packet.message_id = hexi::endian::big_to_native(message_id);

    // Read and convert data_values count
    uint32_t data_count;
    stream.read(&data_count);
    data_count = hexi::endian::big_to_native(data_count);

    // Read and convert data_values
    packet.data_values.resize(data_count);
    stream.read_container(packet.data_values);
    for (uint16_t& value : packet.data_values) {
        value = hexi::endian::big_to_native(value);
    }

    // Read and convert checksum
    uint32_t checksum;
    stream.read(&checksum);
    packet.checksum = hexi::endian::big_to_native(checksum);

    return packet;
}

struct ProtocolHeader {
    uint32_t message_id;
};

ProtocolHeader extract_protocol_header(const std::span<const uint8_t> buffer) {
    ProtocolHeader header;

    // Create a buffer and binary stream for reading
    std::vector<uint8_t> non_const_buffer(buffer.begin(), buffer.end());
    hexi::binary_stream stream(non_const_buffer);

    // Use span to get message_id and convert
    auto message_id_span = stream.span<uint32_t>(1);
    header.message_id = hexi::endian::big_to_native(message_id_span[0]);

    // Skip past the header (4 bytes)
    stream.skip(4);

    return header;
}

