struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Serialization: write sensor_id directly
        adaptor.write(sensor_id);

        // Convert and write each temperature with runtime endianness conversion
        for (auto temp : temperatures) {
            auto converted = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(temp);
            adaptor.write(converted);
        }

        // Convert and write pressure with runtime endianness conversion
        auto converted_pressure = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(pressure);
        adaptor.write(converted_pressure);
    }

    void serialise(auto& adaptor) {
        // Deserialization: read sensor_id directly
        adaptor.read(&sensor_id);

        // Read each temperature and convert from little-endian to native
        for (auto& temp : temperatures) {
            float value;
            adaptor.read(&value);
            hexi::endian::little_to_native_inplace(value);
            temp = value;
        }

        // Read pressure and convert from little-endian to native
        double value;
        adaptor.read(&value);
        hexi::endian::little_to_native_inplace(value);
        pressure = value;
    }
};

